import type { HTMLAttributes } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
import type { AvatarProps, AvatarSize, AvatarVariantType } from '../Avatar/Avatar.types';
/**
 * Размеры компонента AvatarGroup.
 * Определяет размер всех аватаров в группе и величину наложения.
 * - small → наложение -4px, отступ до числа 4px
 * - medium → наложение -8px, отступ до числа 8px
 */
export type AvatarGroupSize = AvatarSize;
/**
 * Варианты формы компонента AvatarGroup.
 * Определяет форму всех аватаров в группе.
 * - square → квадратные аватары
 * - circle → круглые аватары
 */
export type AvatarGroupVariant = AvatarVariantType;
/**
 * Пропсы для отдельного аватара в группе.
 * Исключаются size и variant, так как они задаются на уровне группы.
 */
export interface AvatarGroupItemProps extends Omit<AvatarProps, 'size' | 'variant' | 'hoverToCircle'> {
}
/**
 * Публичные пропсы компонента AvatarGroup.
 *
 * Компонент отображает группу перекрывающихся аватаров с общими размером и вариантом формы,
 * и опциональным числом справа, показывающим количество скрытых элементов.
 *
 * Максимальное количество видимых аватаров: 7.
 *
 * @example
 * ```tsx
 * <AvatarGroup
 *   size="medium"
 *   variant="circle"
 *   avatars={[
 *     { src: "/avatar1.jpg", alt: "User 1" },
 *     { src: "/avatar2.jpg", alt: "User 2" },
 *     { letter: "ЮС", color: "blue" },
 *   ]}
 *   remainingCount={42}
 * />
 * ```
 */
export interface AvatarGroupProps extends TestComponentProps, Omit<HTMLAttributes<HTMLDivElement>, 'children' | 'onClick' | 'ref'> {
    /**
     * Размер всех аватаров в группе.
     * Также определяет величину наложения и отступ до числа:
     * - small → наложение -4px, отступ до числа 4px
     * - medium → наложение -8px, отступ до числа 8px
     * @default 'medium'
     */
    size?: AvatarGroupSize;
    /**
     * Форма всех аватаров в группе.
     * @default 'circle'
     */
    variant?: AvatarGroupVariant;
    /**
     * Массив пропсов для аватаров в группе.
     * Размер и вариант формы будут применены автоматически из пропсов компонента.
     * Максимальное количество видимых аватаров: 7.
     */
    avatars: AvatarGroupItemProps[];
    /**
     * Количество оставшихся элементов (не отображенных в группе).
     * Если задано, отображается справа от группы в формате "+{count}".
     * Если не задано или равно 0, не отображается.
     * Если задан maxVisible и количество аватаров превышает его, вычисляется автоматически.
     */
    remainingCount?: number;
    /**
     * Максимальное количество видимых аватаров.
     * Если количество аватаров превышает maxVisible, остальные скрываются,
     * а их количество отображается в remainingCount (если он не задан явно).
     * Максимальное значение: 7.
     * @default 7
     */
    maxVisible?: number;
    /**
     * Событие клика по компоненту (по всей группе).
     */
    onClick?: () => void;
    /**
     * Пользовательский класс.
     */
    className?: string;
    /**
     * Идентификатор для тестов.
     * @default 'AvatarGroup'
     */
    dataTestId?: string;
}
